SELECT COUNT(variation_id) AS variation_count
FROM genomic_variations
WHERE project_id = 1;

SELECT variation_id
FROM genomic_variations
WHERE quality_score > 90 AND project_id = 1;

SELECT AVG(coverage) AS average_coverage
FROM coverage_data
WHERE sample_id = 1;

SELECT region_id
FROM genomic_region_set_members
WHERE region_set_id = 0 AND date_added = '2023-01-01';

SELECT AVG(quality_score) AS average_quality_score
FROM genomic_variations
WHERE project_id = 1 AND callability = 'callable';

SELECT region_id, AVG(coverage) AS average_coverage
FROM coverage_data
GROUP BY region_id;

SELECT region_id, AVG(coverage) AS average_coverage
  FROM coverage_data
  WHERE region_id = 0;

SELECT region_id, coverage
FROM coverage_data
WHERE sample_id = 2 AND date_collected = '2023-05-02';
